har(128) // SHA-256 of normalized request body\n  responseStatus Int\n  responseBody   Json?\n  createdAt      DateTime @default(now())\n  expiresAt      DateTime\n\n  @@index([expiresAt])\n  @@index([scope, userId])\n  @@map(\"idempotency_keys\")\n}\n\n// =====================================================================\n// AUDIT LOGGING (Lab 4)\n// =====================================================================\n\nmodel AuditEvent {\n  id         String   @id @default(uuid()) @db.Uuid\n  actorId    String   @db.Uuid\n  entityType String   @db.VarChar(64) // e.g. \"User\", \"Subject\"\n  entityId   String   @db.Uuid\n  action     String   @db.VarChar(32) // e.g. \"CREATE\", \"UPDATE\", \"DELETE\"\n  diff       Json? // Stores what changed\n  createdAt  DateTime @default(now())\n\n  @@index([entityType, entityId])\n  @@index([actorId])\n  @@index([createdAt])\n  @@map(\"audit_events\")\n}\n",
